#endif

#ifndef INODE_SYMLINK
#define INODE_SYMLINK 3
#endif

#ifndef DIRNAMELEN
#define DIRNAMELEN 30
#endif

#ifndef MAX_OPEN_FILES
#define MAX_OPEN_FILES 64
#endif

#define MAX_INODES 512
#define MAX_SYMLINK_DEPTH 32

struct dir_entry {
    short inum;
    char name[DIRNAMELEN];
};

struct Stat {
    int inum;
    int type;
    int size;
    int nlink;
};

typedef struct Node Node;

typedef struct {
    int used;
    int inum;
    char name[DIRNAMELEN + 1];
} DirSlot;

struct Node {
    int inum;
    int type;
    int nlink;
    int size;
    int reuse;
